const msg=$input.all()[0].json.message||$input.all()[0].json;
const text=(msg.text||'').trim();
const chatId=msg.chat?msg.chat.id:'';

const sektorMap={'software-dev':'Yazilim Gelistirme','marketing':'Pazarlama','design':'Tasarim','data':'Veri Bilimi','devops-sysadmin':'DevOps','customer-support':'Musteri Destek','finance-legal':'Finans/Hukuk','hr':'Insan Kaynaklari','product':'Urun Yonetimi','qa':'Kalite/Test','writing':'Icerik/Yazarlik'};

let komut='gecersiz',data={};
if(text.startsWith('/sektor ')){komut='sektor';const s=text.replace('/sektor ','').trim();data={Ayar:'sektor',Deger:s,Aciklama:sektorMap[s]||s,sektor:s,sektorAdi:sektorMap[s]||s};}
else if(text==='/sektorler'){komut='sektorler';data={liste:Object.entries(sektorMap).map(([k,v])=>k+' → '+v).join('\n')};}
else if(text==='/ara'){komut='ara';}
return [{json:{komut,chatId,...data}}];

