// Son eklenen degeri kullan (en alttaki satir guncel ayar)
const items=$input.all();
let ayarlar={};
items.forEach(item=>{
  const ayar=item.json['Ayar']||'';
  const deger=item.json['Deger']||'';
  if(ayar)ayarlar[ayar]=deger;
});

const sektor=ayarlar['sektor']||'software-dev';
const profil={
  pozisyon:ayarlar['pozisyon']||'Full Stack Developer',
  deneyim:ayarlar['deneyim']||'2',
  beceriler:ayarlar['beceriler']||'JavaScript,React,Node.js,Python,SQL,Git',
  roller:ayarlar['roller']||'Frontend Developer,Full Stack Developer,Web Developer'
};

return [{json:{sektor,profil,remotiveUrl:'https://remotive.com/api/remote-jobs?category='+sektor+'&limit=15'}}];

const profil=$('Ayarlari Hazirla').first().json.profil;
const remotiveRaw=$('Remotive API').first().json;
const arbeitnowRaw=$('Arbeitnow API').first().json;
let ilanlar=[];
if(remotiveRaw.jobs&&remotiveRaw.jobs.length>0){remotiveRaw.jobs.slice(0,10).forEach(j=>{const a=(j.description||'').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').replace(/[\r\n]+/g,' ').replace(/"/g,"'").trim().substring(0,250);ilanlar.push({kaynak:'Remotive',baslik:(j.title||'').replace(/"/g,"'"),sirket:(j.company_name||'').replace(/"/g,"'"),url:j.url||'',etiketler:(j.tags||[]).join(', '),aciklama:a});});}
if(arbeitnowRaw.data&&arbeitnowRaw.data.length>0){arbeitnowRaw.data.slice(0,10).forEach(j=>{const a=(j.description||'').replace(/<[^>]*>/g,' ').replace(/\s+/g,' ').replace(/[\r\n]+/g,' ').replace(/"/g,"'").trim().substring(0,250);ilanlar.push({kaynak:'Arbeitnow',baslik:(j.title||'').replace(/"/g,"'"),sirket:(j.company_name||'').replace(/"/g,"'"),url:j.url||'',etiketler:(j.tags||[]).join(', '),aciklama:a});});}
const ozetler=ilanlar.map((il,i)=>(i+1)+'. ['+il.kaynak+'] '+il.baslik+' - '+il.sirket+(il.etiketler?' | '+il.etiketler:'')+' -- '+il.aciklama).join(' ||| ');
const promptText='Sen kariyer danismanisin. Turkce yanit ver. PROFIL: '+profil.pozisyon+', '+profil.deneyim+' yil, Beceriler: '+profil.beceriler+', Roller: '+profil.roller+'. ILANLAR ('+ilanlar.length+'): '+ozetler+'. Her ilan icin JSON dondur [{sira,uygunluk_puani:1-10,eslesen_beceriler:[],neden,basvuru_tavsiyesi}] SADECE JSON.';
return [{json:{promptText,ilanlar,toplamIlan:ilanlar.length,tarih:new Date().toLocaleDateString('tr-TR')}}];

const gemini=$input.all()[0].json;const ilanlar=$('Ilanlari Topla').first().json.ilanlar;const tarih=$('Ilanlari Topla').first().json.tarih;
let analizler=[];
try{let m=gemini.candidates[0].content.parts[0].text;const j=m.match(/\[\s*\{[\s\S]*\}\s*\]/);if(j)analizler=JSON.parse(j[0]);}catch(e){analizler=ilanlar.map((_,i)=>({sira:i+1,uygunluk_puani:5,eslesen_beceriler:[],neden:'Analiz okunamadi',basvuru_tavsiyesi:'Manuel kontrol'}));}
const sonuclar=[];
for(let i=0;i<ilanlar.length;i++){const a=analizler[i]||{uygunluk_puani:0};sonuclar.push({json:{tarih,kaynak:ilanlar[i].kaynak,baslik:ilanlar[i].baslik,sirket:ilanlar[i].sirket,url:ilanlar[i].url,uygunluk_puani:a.uygunluk_puani||0,eslesen_beceriler:(a.eslesen_beceriler||[]).join(', '),neden:a.neden||'',tavsiye:a.basvuru_tavsiyesi||'',kategori:a.uygunluk_puani>=7?'Yuksek':a.uygunluk_puani>=4?'Orta':'Dusuk'}});}
sonuclar.sort((a,b)=>b.json.uygunluk_puani-a.json.uygunluk_puani);
return sonuclar;

